import{_ as r,o as t,c as a,a2 as s}from"./chunks/framework.Crpw6aS5.js";const i="data:image/svg+xml,%3c?xml%20version='1.0'%20encoding='UTF-8'?%3e%3csvg%20id='Calque_1'%20xmlns='http://www.w3.org/2000/svg'%20viewBox='0%200%20512%20512'%3e%3cpath%20d='M394.28,207.8c.81,2.41,1.39,4.78,1.8,7.07,1.61,9.03-.93,17.78-5.99,21.74-22.6,17.7-49.85,29.35-75.34,38.6-.59.22-1.09.28-1.4.34-2.22.47-4.95,1.04-7.25,0-1.46-.66-2.25-1.74-2.66-2.3-1.56-2.1-1.59-4.31-1.56-5.13.1-2.67-.01-4.69,0-4.82.45-3.52.91-10.66,1.41-21.28.6-3.87,2.16-9.63,6.94-13.96,4.01-3.62,8.33-4.6,14.59-5.87,10.76-2.19,37.21-8.22,47.42-16.56,1.63-1.33,2.97-2.65,4.19-3.96,3.72-3.99,6.39-7.92,7.93-10.36,3.22,3.22,7.25,8.48,9.92,16.47Z'/%3e%3cpath%20d='M428.67,185.28c-2.33,11.99-8.91,22.32-15.88,30.38.27-5.5-.05-12.11-1.86-19.08-5.04-19.36-19.74-34.7-37.78-37.78-32.21-9.74-70.59,3.79-99.08,18.29-3.87,1.95-9.52-2.77-11.84-8.16-3.32-7.71-1.63-6.28,2.61-8.49,38.31-20.03,82.01-39.61,123.91-29.7,8.26,1.95,15.96,5.26,23.48,10.54,11.32,7.96,20.21,24.74,16.44,44Z'/%3e%3cpath%20d='M117.72,304.2c-.81-2.41-1.39-4.78-1.8-7.07-1.61-9.03.93-17.78,5.99-21.74,22.6-17.7,49.85-29.35,75.34-38.6.59-.22,1.09-.28,1.4-.34,2.22-.47,4.95-1.04,7.25,0,1.46.66,2.25,1.74,2.66,2.3,1.56,2.1,1.59,4.31,1.56,5.13-.1,2.67.01,4.69,0,4.82-.45,3.52-.91,10.66-1.41,21.28-.6,3.87-2.16,9.63-6.94,13.96-4.01,3.62-8.33,4.6-14.59,5.87-10.76,2.19-37.21,8.22-47.42,16.56-1.63,1.33-2.97,2.65-4.19,3.96-3.72,3.99-6.39,7.92-7.93,10.36-3.22-3.22-7.25-8.48-9.92-16.47Z'/%3e%3cpath%20d='M83.33,326.72c2.33-11.99,8.91-22.32,15.88-30.38-.27,5.5.05,12.11,1.86,19.08,5.04,19.36,19.74,34.7,37.78,37.78,32.21,9.74,70.59-3.79,99.08-18.29,3.87-1.95,9.52,2.77,11.84,8.16,3.32,7.71,1.63,6.28-2.61,8.49-38.31,20.03-82.01,39.61-123.91,29.7-8.26-1.95-15.96-5.26-23.48-10.54-11.32-7.96-20.21-24.74-16.44-44Z'/%3e%3cellipse%20cx='255.16'%20cy='258.86'%20rx='28.95'%20ry='28.76'/%3e%3c/svg%3e",o="/assets/02-app-icon.CT3QclcX.png",b=JSON.parse('{"title":"Superpowers Skills Library (obra/superpowers)","description":"Imported notes on the Superpowers agent methodology and its composable skills library.","frontmatter":{"title":"Superpowers Skills Library (obra/superpowers)","description":"Imported notes on the Superpowers agent methodology and its composable skills library."},"headers":[],"relativePath":"misc/artificial-intelligence/github-obra-superpowers-skills.md","filePath":"misc/artificial-intelligence/github-obra-superpowers-skills.md"}'),n={name:"misc/artificial-intelligence/github-obra-superpowers-skills.md"};function l(p,e,c,d,g,h){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="superpowers-skills-library-obra-superpowers" tabindex="-1">Superpowers Skills Library (obra/superpowers) <a class="header-anchor" href="#superpowers-skills-library-obra-superpowers" aria-label="Permalink to &quot;Superpowers Skills Library (obra/superpowers)&quot;">​</a></h1><p><img src="'+i+'" alt="Superpowers logo"></p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://github.com/obra/superpowers/tree/main/skills" target="_blank" rel="noreferrer">https://github.com/obra/superpowers/tree/main/skills</a></li><li>Imported: 2025-06-25</li><li>Images: 2 (logo SVG and app icon PNG saved under <code>./assets/github-obra-superpowers-skills/</code>)</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><p><a href="https://github.com/obra/superpowers" target="_blank" rel="noreferrer">Superpowers</a> is a complete software development methodology for coding agents, built on composable skills and bootstrap instructions that ensure the agent uses them automatically.</p><p><img src="'+o+'" alt="Superpowers app icon"></p><h3 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h3><p>When you start a coding agent session, Superpowers does not jump straight into writing code. Instead it:</p><ol><li>Steps back and asks what you are really trying to do.</li><li>Teases out a spec through conversation, then shows it in digestible chunks.</li><li>After design sign-off, produces an implementation plan clear enough for a junior engineer with no project context to follow — emphasizing red/green TDD, YAGNI, and DRY.</li><li>On &quot;go&quot;, launches <strong>subagent-driven-development</strong> (or <strong>executing-plans</strong>): agents work through tasks, inspect and review work, and continue autonomously — often for hours without deviating from the plan.</li></ol><p>Skills trigger automatically; no special invocation is required once installed.</p><h3 id="installation-cursor" tabindex="-1">Installation (Cursor) <a class="header-anchor" href="#installation-cursor" aria-label="Permalink to &quot;Installation (Cursor)&quot;">​</a></h3><p>In Cursor Agent chat:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/add-plugin superpowers</span></span></code></pre></div><p>Or search for &quot;superpowers&quot; in the plugin marketplace.</p><p>Other harnesses (Claude Code, Codex, Gemini CLI, Copilot CLI, Pi, OpenCode, etc.) have separate install paths — see the <a href="https://github.com/obra/superpowers#installation" target="_blank" rel="noreferrer">full README</a>.</p><h3 id="the-basic-workflow" tabindex="-1">The basic workflow <a class="header-anchor" href="#the-basic-workflow" aria-label="Permalink to &quot;The basic workflow&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Step</th><th>Skill</th><th>What it does</th></tr></thead><tbody><tr><td>1</td><td><strong>brainstorming</strong></td><td>Refines rough ideas through questions, explores alternatives, presents design in sections for validation. Saves a design document.</td></tr><tr><td>2</td><td><strong>using-git-worktrees</strong></td><td>After design approval, creates an isolated workspace on a new branch, runs project setup, verifies a clean test baseline.</td></tr><tr><td>3</td><td><strong>writing-plans</strong></td><td>With approved design, breaks work into bite-sized tasks (2–5 minutes each) with exact file paths, complete code, and verification steps.</td></tr><tr><td>4</td><td><strong>subagent-driven-development</strong> or <strong>executing-plans</strong></td><td>Dispatches a fresh subagent per task with two-stage review (spec compliance, then code quality), or executes in batches with human checkpoints.</td></tr><tr><td>5</td><td><strong>test-driven-development</strong></td><td>Enforces RED-GREEN-REFACTOR during implementation: write failing test, watch it fail, write minimal code, watch it pass, commit.</td></tr><tr><td>6</td><td><strong>requesting-code-review</strong></td><td>Between tasks, reviews against the plan and reports issues by severity. Critical issues block progress.</td></tr><tr><td>7</td><td><strong>finishing-a-development-branch</strong></td><td>When tasks complete, verifies tests, presents options (merge/PR/keep/discard), cleans up worktree.</td></tr></tbody></table><p>The agent checks for relevant skills before any task. These are mandatory workflows, not suggestions.</p><h3 id="skills-library" tabindex="-1">Skills library <a class="header-anchor" href="#skills-library" aria-label="Permalink to &quot;Skills library&quot;">​</a></h3><p>All skills live under <a href="https://github.com/obra/superpowers/tree/main/skills" target="_blank" rel="noreferrer"><code>skills/</code></a> in the repository.</p><h4 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h4><ul><li><a href="https://github.com/obra/superpowers/blob/main/skills/test-driven-development/SKILL.md" target="_blank" rel="noreferrer"><strong>test-driven-development</strong></a> — RED-GREEN-REFACTOR cycle. Write the test first, watch it fail, write minimal code to pass. Includes testing anti-patterns reference. Use for new features, bug fixes, refactoring, and behavior changes.</li></ul><h4 id="debugging" tabindex="-1">Debugging <a class="header-anchor" href="#debugging" aria-label="Permalink to &quot;Debugging&quot;">​</a></h4><ul><li><a href="https://github.com/obra/superpowers/blob/main/skills/systematic-debugging/SKILL.md" target="_blank" rel="noreferrer"><strong>systematic-debugging</strong></a> — Four-phase root cause process. <strong>Iron law:</strong> no fixes without root cause investigation first. Includes root-cause-tracing, defense-in-depth, and condition-based-waiting techniques.</li><li><a href="https://github.com/obra/superpowers/blob/main/skills/verification-before-completion/SKILL.md" target="_blank" rel="noreferrer"><strong>verification-before-completion</strong></a> — Evidence before claims. Run fresh verification commands before declaring work complete, fixed, or passing.</li></ul><h4 id="collaboration" tabindex="-1">Collaboration <a class="header-anchor" href="#collaboration" aria-label="Permalink to &quot;Collaboration&quot;">​</a></h4><ul><li><a href="https://github.com/obra/superpowers/blob/main/skills/brainstorming/SKILL.md" target="_blank" rel="noreferrer"><strong>brainstorming</strong></a> — Socratic design refinement before any creative work. Hard gate: no implementation until design is presented and approved.</li><li><a href="https://github.com/obra/superpowers/blob/main/skills/writing-plans/SKILL.md" target="_blank" rel="noreferrer"><strong>writing-plans</strong></a> — Detailed implementation plans for multi-step tasks. Saves to <code>docs/superpowers/plans/YYYY-MM-DD-&lt;feature-name&gt;.md</code>.</li><li><a href="https://github.com/obra/superpowers/blob/main/skills/executing-plans/SKILL.md" target="_blank" rel="noreferrer"><strong>executing-plans</strong></a> — Batch execution with review checkpoints in a separate session. Prefer <strong>subagent-driven-development</strong> when subagents are available.</li><li><a href="https://github.com/obra/superpowers/blob/main/skills/dispatching-parallel-agents/SKILL.md" target="_blank" rel="noreferrer"><strong>dispatching-parallel-agents</strong></a> — One agent per independent problem domain when facing 2+ unrelated failures that can run concurrently.</li><li><a href="https://github.com/obra/superpowers/blob/main/skills/requesting-code-review/SKILL.md" target="_blank" rel="noreferrer"><strong>requesting-code-review</strong></a> — Dispatch a reviewer subagent with crafted context. Mandatory after each subagent-driven task and before merge.</li><li><a href="https://github.com/obra/superpowers/blob/main/skills/receiving-code-review/SKILL.md" target="_blank" rel="noreferrer"><strong>receiving-code-review</strong></a> — Verify before implementing feedback. Technical correctness over performative agreement.</li><li><a href="https://github.com/obra/superpowers/blob/main/skills/using-git-worktrees/SKILL.md" target="_blank" rel="noreferrer"><strong>using-git-worktrees</strong></a> — Isolated workspace via native tools or git worktree fallback. Detect existing isolation before creating anything new.</li><li><a href="https://github.com/obra/superpowers/blob/main/skills/finishing-a-development-branch/SKILL.md" target="_blank" rel="noreferrer"><strong>finishing-a-development-branch</strong></a> — Verify tests → detect environment → present merge/PR/keep/discard options → execute → clean up.</li><li><a href="https://github.com/obra/superpowers/blob/main/skills/subagent-driven-development/SKILL.md" target="_blank" rel="noreferrer"><strong>subagent-driven-development</strong></a> — Fresh subagent per task + task review (spec + quality) + broad final review. Continuous execution without pausing between tasks.</li></ul><h4 id="meta" tabindex="-1">Meta <a class="header-anchor" href="#meta" aria-label="Permalink to &quot;Meta&quot;">​</a></h4><ul><li><a href="https://github.com/obra/superpowers/blob/main/skills/writing-skills/SKILL.md" target="_blank" rel="noreferrer"><strong>writing-skills</strong></a> — TDD applied to process documentation. Create, edit, and verify skills before deployment.</li><li><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md" target="_blank" rel="noreferrer"><strong>using-superpowers</strong></a> — Bootstrap skill loaded at session start. If a skill might apply (even 1% chance), you must invoke it. User instructions override skill defaults.</li></ul><h3 id="philosophy" tabindex="-1">Philosophy <a class="header-anchor" href="#philosophy" aria-label="Permalink to &quot;Philosophy&quot;">​</a></h3><ul><li><strong>Test-Driven Development</strong> — Write tests first, always.</li><li><strong>Systematic over ad-hoc</strong> — Process over guessing.</li><li><strong>Complexity reduction</strong> — Simplicity as primary goal.</li><li><strong>Evidence over claims</strong> — Verify before declaring success.</li></ul><h3 id="related-links" tabindex="-1">Related links <a class="header-anchor" href="#related-links" aria-label="Permalink to &quot;Related links&quot;">​</a></h3><ul><li><a href="https://blog.fsck.com/2025/10/09/superpowers/" target="_blank" rel="noreferrer">Original release announcement</a></li><li><a href="https://github.com/obra/superpowers-marketplace" target="_blank" rel="noreferrer">Superpowers marketplace</a> (Claude Code / Copilot CLI)</li><li><a href="https://github.com/prime-radiant-inc/superpowers-evals/" target="_blank" rel="noreferrer">superpowers-evals</a> — skill-behavior test harness</li><li><a href="https://discord.gg/35wsABTejz" target="_blank" rel="noreferrer">Discord community</a></li><li><a href="https://primeradiant.com/superpowers/" target="_blank" rel="noreferrer">Release announcements signup</a></li></ul><h3 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h3><p>MIT License — see <a href="https://github.com/obra/superpowers/blob/main/LICENSE" target="_blank" rel="noreferrer">LICENSE</a>.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Superpowers is a composable agent methodology: design → plan → isolated worktree → TDD implementation → review → branch completion.</li><li>Fourteen skills under <code>skills/</code> cover testing, debugging, collaboration, and meta skill authoring; they auto-trigger once the plugin is installed.</li><li>Cursor install: <code>/add-plugin superpowers</code> or search the plugin marketplace.</li><li>Core philosophy: TDD, systematic debugging, simplicity, and evidence-based completion claims.</li><li>Two branding assets (SVG logo + PNG app icon) are saved locally under <code>assets/github-obra-superpowers-skills/</code>.</li></ul>',37)])])}const m=r(n,[["render",l]]);export{b as __pageData,m as default};
